import subprocess
import re
import sys
from pathlib import Path

def get_changed_files() -> list[str]:
    result = subprocess.run(
        ["git", "diff", "--name-only", "origin/main...HEAD"],
        capture_output=True, text=True
    )
    return result.stdout.strip().split("\n")

def extract_adr_reference(filepath: str) -> list[str]:
    # Convention: deployment config files reference their ADR in a comment
    # Example: # requires-adr: ADR-001, ADR-003
    content = Path(filepath).read_text()
    matches = re.findall(r"requires-adr:\s*(ADR-\d+(?:,\s*ADR-\d+)*)", content)
    adrs = []
    for match in matches:
        adrs.extend(a.strip() for a in match.split(","))
    return adrs

def check_adr_status(adr_id: str, adr_dir: Path) -> str:
    # Find the ADR file and extract its status
    matches = list(adr_dir.glob(f"{adr_id}-*.md"))
    if not matches:
        return "NOT_FOUND"
    content = matches[0].read_text()
    status_match = re.search(r"Status:\*\*\s+(\w+)", content)
    return status_match.group(1) if status_match else "UNKNOWN"

def gate_deployment(adr_dir: Path = Path("docs/adr")) -> None:
    changed = get_changed_files()
    blocked = []
    for filepath in changed:
        if not Path(filepath).exists():
            continue
        required_adrs = extract_adr_reference(filepath)
        for adr_id in required_adrs:
            status = check_adr_status(adr_id, adr_dir)
            if status != "Accepted":
                blocked.append(f"{filepath} requires {adr_id} (status: {status})")

    if blocked:
        print("DEPLOYMENT BLOCKED: unapproved ADR dependencies")
        for b in blocked:
            print(f"  - {b}")
        sys.exit(1)
    else:
        print("ADR gate: all required ADRs are Accepted")

